class Solution:
    def twoSum(self, nums: List[int], target: int) -> List[int]:
        hash_map = {}
        for index, num in enumerate(nums):
            complement = target - num
            if complement in hash_map:
                return [hash_map[complement], index]
            hash_map[num] = index

        return []

class Solution:
    def lengthOfLongestSubstring(self, s: str) -> int:
        char_map = {}
        left = 0
        max_length = 0

        for right, char in enumerate(s):
            if char in char_map and char_map[char] >= left:
                left = char_map[char] + 1
            char_map[char] = right
            max_length = max(max_length, right - left + 1)

        return max_length

class Solution:
    def findMedianSortedArrays(self, nums1: List[int], nums2: List[int]) -> float:
        def getKth(k):
            i = j = 0
            while True:
                if i == len(nums1): return nums2[j + k]
                if j == len(nums2): return nums1[i + k]
                if k == 0: return min(nums1[i], nums2[j])

                half = (k + 1) // 2
                ni = min(i + half, len(nums1))
                nj = min(j + half, len(nums2))

                if nums1[ni - 1] < nums2[nj - 1]:
                    k -= ni - i
                    i = ni
                else:
                    k -= nj - j
                    j = nj

        total = len(nums1) + len(nums2)
        if total % 2 == 1:
            return getKth(total // 2)
        else:
            return (getKth(total//2 - 1) + getKth(total//2)) / 2

class Solution:
    def convert(self, s: str, numRows: int) -> str:
        if numRows == 1 or numRows >= len(s):
            return s

        rows = [''] * numRows
        cur = 0
        down = False

        for c in s:
            rows[cur] += c
            if cur == 0 or cur == numRows - 1:
                down = not down
            cur += 1 if down else -1

        return ''.join(rows)

class Solution:
    def myAtoi(self, s: str) -> int:
        INT_MIN, INT_MAX = -2**31, 2**31 - 1
        i, n = 0, len(s)

        while i < n and s[i] == ' ':
            i += 1

        if i >= n:
            return 0

        sign = 1
        if s[i] in '+-':
            sign = -1 if s[i] == '-' else 1
            i += 1

        result = 0
        while i < n and s[i].isdigit():
            digit = int(s[i])
            if result > (INT_MAX - digit) // 10:
                return INT_MAX if sign == 1 else INT_MIN
            result = result * 10 + digit
            i += 1

        return sign * result

class Solution:
    def strStr(self, haystack: str, needle: str) -> int:
        length = len(needle)
        kmp = [0] * length
        for i in range(1, length):
            j = kmp[i - 1]
            while j > 0 and needle[i] != needle[j]:
                j = kmp[j - 1]
            if needle[i] == needle[j]:
                j += 1
            kmp[i] = j

        j = 0
        for i in range(len(haystack)):
            while j > 0 and haystack[i] != needle[j]:
                j = kmp[j - 1]
            if haystack[i] == needle[j]:
                j += 1
            if j == length:
                return i - length + 1
        return -1

class Solution:
    def isValidSudoku(self, board: List[List[str]]) -> bool:
        seen = set()

        for row in range(9):
            for col in range(9):
                num = board[row][col]
                if num == '.':
                    continue

                row_key = f"({num}) in row {row}"
                col_key = f"({num}) in column {col}"
                box_key = f"({num}) in box {(row // 3) * 3 + (col // 3)}"

                if row_key in seen or col_key in seen or box_key in seen:
                    return False

                seen.add(row_key)
                seen.add(col_key)
                seen.add(box_key)

        return True

class Solution:
    def trap(self, height: List[int]) -> int:
        left, right = 0, len(height) - 1
        left_max = right_max = water = 0

        while left < right:
            if height[left] < height[right]:
                if height[left] >= left_max:
                    left_max = height[left]
                else:
                    water += left_max - height[left]
                left += 1
            else:
                if height[right] >= right_max:
                    right_max = height[right]
                else:
                    water += right_max - height[right]
                right -= 1

        return water

class Solution:
    def rotate(self, matrix: List[List[int]]) -> None:
        """
        Do not return anything, modify matrix in-place instead.
        """
        n = len(matrix)

        for i in range(n):
            for j in range(i + 1, n):
                matrix[i][j], matrix[j][i] = matrix[j][i], matrix[i][j]

        for i in range(n):
            matrix[i].reverse()

class Solution:
    def mySqrt(self, x: int) -> int:
        if x < 2:
            return x

        left, right = 2, x // 2
        while left <= right:
            pivot = left + (right - left) // 2
            num = pivot * pivot

            if num > x:
                right = pivot - 1
            elif num < x:
                left = pivot + 1
            else:
                return pivot

        return right

class Solution:
    def climbStairs(self, n: int) -> int:
        if n <= 2:
            return n
        a, b = 1, 2

        for _ in range(3, n + 1):
            a, b = b, a + b

        return b
